0.text:
Async patterns for Sairin.
useDeferred
Defer signal updates to the next tick.
import { signal, useDeferred, path } from &#x27;sairin&#x27;;

const count = signal(path(&quot;counter&quot;), 0);
const deferred = useDeferred(count);

count.set(1);  // deferred still 0
count.set(2);  // deferred still 0

// After microtask:
console.log(deferred.get());  // 2

Options
useDeferred(signal, { timeoutMs: 1000 });
// Forces update after timeout if no changes

useDeferredValue
Defer a value, creating a signal.
import { useDeferredValue, signal } from &#x27;sairin&#x27;;

const deferred = useDeferredValue(42);
console.log(deferred.get());  // 42

With signal:
const source = signal(path(&quot;source&quot;), &quot;hello&quot;);
const deferred = useDeferredValue(source);

resource
Async data fetching with loading/error states.
import { resource } from &#x27;sairin&#x27;;

const userResource = resource(async (signal) =&gt; {
  const res = await fetch(&quot;/api/user&quot;, { signal });
  return res.json();
});

Returns
interface Resource&lt;T&gt; {
  loading: Signal&lt;boolean&gt;;
  error: Signal&lt;Error | null&gt;;
  data: Signal&lt;T | null&gt;;
  read: () =&gt; T | null;
  reload: () =&gt; void;
  abort: () =&gt; void;
}

Usage
const user = userResource.read();

userResource.loading.get();  // true/false
userResource.error.get();    // Error or null
userResource.data.get();     // T or null

userResource.reload();

userResource.abort();

1.text:
Async flow control utilities.
flow
Execute an async operation with state signals.
import { flow } from &#x27;sairin&#x27;;

const fetchUser = flow(async (signal) =&gt; {
  const response = await fetch(&quot;/api/user&quot;, { signal });
  return response.json();
});

Returns
interface Flow&lt;T&gt; {
  running: Signal&lt;boolean&gt;;
  result: Signal&lt;T | null&gt;;
  error: Signal&lt;Error | null&gt;;
  start: () =&gt; Promise&lt;void&gt;;
  cancel: () =&gt; void;
}

Usage
await fetchUser.start();

console.log(fetchUser.running.get());  // false
console.log(fetchUser.result.get());    // { ... }
console.log(fetchUser.error.get());     // null or Error

fetchUser.cancel();

pipeline
Async operation with input.
import { pipeline } from &#x27;sairin&#x27;;

const processData = pipeline(async (input, signal) =&gt; {
  const result = await fetch(`/api/process/${input}`, { signal });
  return result.json();
});

Returns
interface Pipeline&lt;T, R&gt; {
  running: Signal&lt;boolean&gt;;
  result: Signal&lt;R | null&gt;;
  error: Signal&lt;Error | null&gt;;
  start: (input: T) =&gt; Promise&lt;void&gt;;
  cancel: () =&gt; void;
}

sequence
Run functions in sequence, collect all results.
import { sequence } from &#x27;sairin&#x27;;

const seq = sequence(
  async () =&gt; &quot;a&quot;,
  async () =&gt; &quot;b&quot;,
  async () =&gt; &quot;c&quot;
);

await seq.start();

console.log(seq.results.get());  // [&quot;a&quot;, &quot;b&quot;, &quot;c&quot;]
console.log(seq.errors.get());    // []

parallel
Run functions in parallel.
import { parallel } from &#x27;sairin&#x27;;

const par = parallel(
  () =&gt; fetch(&quot;/api/1&quot;),
  () =&gt; fetch(&quot;/api/2&quot;),
  () =&gt; fetch(&quot;/api/3&quot;)
);

await par.start();

race
First to settle wins.
import { race } from &#x27;sairin&#x27;;

const winner = race(
  () =&gt; fetch(&quot;/api/fast&quot;),
  () =&gt; fetch(&quot;/api/slow&quot;)
);

await winner.start();

console.log(winner.winner.get());  // 0 or 1

