Connect Satori for structured logging:
import { createSatori } from &#x27;@nisoku/satori-log&#x27;;
import { configureSairin } from &#x27;sairin&#x27;;

const satori = createSatori({
  logLevel: &#x27;info&#x27;,
});

configureSairin({
  satori,
});

